var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아이 씨……. 역시 내가 너무 심하게 말했나…….","JPN":"むう……やっぱり言いすぎたかな……","ENG":"Argh… Was I out of line back there?","TWN":"可惡……我說得太過火了嗎……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"민우 아저씨 생각에는 어때요? 그 정상 참참인가 안 돼요?","JPN":"マツダおじさんはどう思います？　その、じょーじょーしゃくりょなんちゃらっていうものはダメ？","ENG":"What do you think, Mr. Minwoo? You think this counts as an extenuary circumcision?","TWN":"民宇叔叔，你覺得呢？這樣不算情無可原嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……엠마를 돌볼 사람 필요하다고 따라온 거 아니었나?","JPN":"……エマにはお世話をする人が必要と言って付いてきたんじゃなかったか？","ENG":"Didn't you tag along because Emma needs a caretaker?","TWN":"……你不是來照顧愛瑪的嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아까부터 자기 고민 상담만 신나게 하는 것 같다만.","JPN":"さっきから自分の悩み相談で盛り上がっているようだが。","ENG":"It feels more like you're here to vent.","TWN":"但你從剛才就一直在說自己的事。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"치. 엠마가 눈 하나 깜빡하는 것까지 계속 보고 있걸랑요.","JPN":"ちっ、エマの瞬きも見逃さずにずっと見ていますよ？","ENG":"Hmph. I've been watching Emma's every move. Including how many times she blinks.","TWN":"拜託，我有顧著好嗎！連愛瑪有沒有眨個眼睛我都一直盯著。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"정확히는 정상 참작이고, 이런 경우에 쓸 말도 아냐.","JPN":"まず、正しくは情状酌量だ。そしてこういう場合に使う言葉ではない。","ENG":"Anyway, it's called \\"extenuating circumstances,\\" and that's not how you're supposed to use it.","TWN":"正確的說法是情有可原，你的情況也不適用情有可原這句話。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"자기가 언니라고 하더니 결국 대판 싸워 버렸군. 어른이고 싶다면 먼저 사과해.","JPN":"自分のことをいつもお姉ちゃんだとか言っておいて大げんかしたんだな。大人になりたければ先に謝ればいい。","ENG":"You were acting like you're the grownup only to end up fighting, huh. You should apologize first if you want to be a real grownup.","TWN":"你自己說你是姊姊，卻又跟人家鬧翻。想成為大人的話，就先道歉。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"제가 왜요. 억지는 맨날 걔가 부리는데.","JPN":"なんでアタシが？　あり得ないことを言ってるのはあの子ですよ？","ENG":"Why should I? She's the one who's being ridiculous all the time.","TWN":"憑什麼？！是她一直要跟我吵欸！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"나는 호라이즌이다~ 젖병 물고 다닐 것처럼 생겼지만 무시무시한 사채업자다~ 으에~","JPN":"アタシはホライズンだぁー見た目は哺乳瓶を持っててもおかしくないガキだけど、実は恐ろしい闇金業者だぞぉーがおぉー","ENG":"Boo, I'm Horizon! I look like a total baby but I'm actually a scary loan shark! Boo!","TWN":"我是地平線～雖然外表看起來像還在喝奶的年紀，但其實是凶狠的高利貸～矮額～"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GIRL_NPC_HORIZON_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GIRL_NPC_HORIZON_NULL","text":{"KOREA":"언니……. 유치해…….","JPN":"お姉ちゃん……子どもみたい……","ENG":"Rachel… You're so immature…","TWN":"姊姊……你好幼稚……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GIRL_NPC_HORIZON_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"흥. 넌 퇴원하면 웃다가 울 때까지 간지럼 형벌인 줄 알아.","JPN":"ふん、あんたには退院したら笑い過ぎて涙が出てくるまでくすぐられる刑が待っているんだからね。","ENG":"Hmph. Once you get all better, I'm going to tickle you to death.","TWN":"哼！等你出院後，罰你搔癢搔到哭出來為止！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GIRL_NPC_HORIZON_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……어쩌면 사실일지도 모르지.","JPN":"……もしかしたら事実かもしれないしな。","ENG":"…She might be telling the truth.","TWN":"……或許，她說的是真的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"네? 그 사채업자 타령이요?","JPN":"え？　闇金業者が？","ENG":"What? You mean all that gibberish about being a loan shark?","TWN":"什麼真的？高利貸喔？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"걔한테 뒷돈이라도 받았어요? 뜬금없이 무슨 소리에요?","JPN":"急にどうしたんですか？　あの子からお金でももらいました？","ENG":"Did she bribe you or something? Where's this even coming from?","TWN":"你是不是有收她的錢？突然胡說八道什麼？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그러는 너는 호라이즌 파이낸스에 대해 얼마나 알지?","JPN":"そんなあんたはホライズン・ファイナンスについてどの程度知っているんだ？","ENG":"Well, exactly how much do you know about Horizon Finance?","TWN":"那你對地平線金融了解多少？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐……. 갱단들도 설설 기던 사채업자라는 것만요.","JPN":"まあ……ギャングでさえ恐れていた闇金業者ってことぐらいは。","ENG":"Well… All I know is that even the gangs were scared of them.","TWN":"嗯…就…是連幫派都不敢得罪的高利貸。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어른들한테 들었어요. 호라이즌 파이낸스가 있을 때는 갱단들도 사람들이랑 눈도 못 마주쳤다고요.","JPN":"大人たちから聞きました。ホライズン・ファイナンスがいた当時は、ギャングも住民に下手な真似ができなかったって。","ENG":"I heard the grownups talk about it. The gangs didn't dare mess with anyone when Horizon Finance was around.","TWN":"我聽大人們說的，說地平線金融還在的時候，那些幫派連和人對到眼都不敢。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"내가 예전 직장에서 들은 이야기는 반군이랑 싸웠다는 거였어.","JPN":"俺が前の職場で聞いた話では、反乱軍と戦ったらしい。","ENG":"In my previous work, I heard that they fought against the insurgency.","TWN":"我在之前的職場中聽到的是，地平線金融和叛軍交火過。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"반군이요? 사채업자가?","JPN":"反乱軍ですか？　闇金業者が？","ENG":"You mean the rebels? A loan shark fought them off?","TWN":"叛軍嗎？高利貸？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 지금의 그로니아처럼 발호했던 군벌 하나를 쑥대밭으로 만들었다더군.","JPN":"そうだ。今のグロニアのような跋扈した軍閥一つをめちゃくちゃにしたらしい。","ENG":"That's right. Apparently they wiped out an entire faction that was as untouchable as Gronia is today.","TWN":"沒錯。我聽說好像單槍匹馬剷平軍閥呢。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"거대 범죄 조직의 면피용 신분이다, 전쟁에서 활약했던 S급 카운터다…….","JPN":"巨大犯罪組織のロビー会社だの、戦争で活躍したS級カウンターだの……","ENG":"Some say it was just a cover for a giant crime organization… While others claim that it's an S-Grade Counter who was a war hero…","TWN":"有人說是用來掩蓋巨大犯罪組織的身分，也有人說是在戰場上很活躍的S級制裁者……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"소문은 무성했지만 실체는 밝혀지지 않았지. 한창 주목 받을 때 종적을 감췄으니까.","JPN":"色んな噂が広まっていたが、実体は明らかになっていない。注目されていたタイミングで急に行方をくらましたからな。","ENG":"There were all sorts of rumors, but nobody found out the truth. They vanished right at the height of their reputation.","TWN":"雖然有各種的傳言，但從未被實際證實過。因為在最引人注意的時候就突然消失不見。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"오오……. 왠지 끗발 있는 느낌…….","JPN":"おお……何か裏がある感じ……","ENG":"Ooh… That sounds pretty badass…","TWN":"喔喔……總覺得有內情……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"잠깐, 그럼 더 말이 안 되잖아요.","JPN":"ちょっと待って、でもそれならもっとおかしくないですか？","ENG":"But hang on, that doesn't make any sense.","TWN":"等等，這樣更不合理吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아저씨 잘 나갈 때 걔는 아이스크림 사 달라고 떼를 쓸지 고민하고 있었을 걸요?","JPN":"おじさんが現役時代、あの子はアイスを買ってほしいと駄々をこねるような年頃だったはずですよ？","ENG":"She was probably chasing after ice cream trucks when you were out there in your prime.","TWN":"叔叔你在職場的時候，他應該還是在吵著要吃冰淇淋的年紀吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"뭐, 어딘가에는 늙지 않는 능력을 가진 카운터도 있겠지.","JPN":"まあ、この世のどこかには年を取らない能力を持つカウンターもいるだろう。","ENG":"Well, maybe some Counters don't age as part of their power.","TWN":"哎唷～可能有些地方的制裁者能力是不會變老吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"레이첼, 그 아이한테 호라이즌 파이낸스에 대해 자세히 물어 본 적 있나?","JPN":"レイチェル、あの子にホライズン・ファイナンスについて詳しく聞いたことはあるか？","ENG":"Rachel, have you ever asked the girl any serious questions about Horizon Finance?","TWN":"瑞秋，你有問過她關於地平線金融的事嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"……아뇨. 물어 본 적 없어요. 괜히 건드리면 자기 망상이 탄로났다고 화낼까 봐.","JPN":"……いいえ、直接聞いたことはないです。余計なこと聞いちゃうと、妄想がバレたと怒られそうで。","ENG":"…No. Not really. I thought she'd get mad if I burst her bubble.","TWN":"……沒有，我沒問過。我怕我問她的話，她會生氣覺得我想太多。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"돌아가는 대로 한 번 물어 봐. 네 생각처럼 망상이라면 그대로 두는 것도 위험하겠지.","JPN":"今度会った時に聞いてみろ。あんたの言うとおり、妄想なら妄想でそのままにしておくのも危ないからな。","ENG":"Why don't you ask the next time you see her? If this is really just an illusion as you think, letting her keep continue this way could get dangerous.","TWN":"你回去後再問問看，如果真的是你想太多，放她自己在那裡也不安全。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"자, 손님 여러분. 우리는 이제 곧 난민지구를 벗어납니다.","JPN":"さあ、お客様。この車はまもなく難民地区から離れます。","ENG":"Well, ladies and gentlemen. We will now leave the refugee district.","TWN":"各位乘客，我們就快要離開難民區囉。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"겨우? 차로 한참 온 것 같은데?","JPN":"まだ？　結構走ってきたと思ったのに。","ENG":"Just now? I feel like we've been driving forever.","TWN":"才快要？不是已經搭很久的車嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"침식지대를 돌아서 가야 하니까 그렇지. 괜히 침식체들 자극할 필요 없잖아.","JPN":"侵食地帯を迂回したからだろう。わざわざ侵食体を刺激しながら移動する必要はないからな。","ENG":"It's because we had to take a detour around the Corrupted Area. There's no need to provoke those C.O.s for no reason.","TWN":"因為要繞過侵蝕地區，沒必要去招惹侵蝕體嘛～"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"안 그렇습니까, 교관님?","JPN":"そう思いませんか、教官？","ENG":"Ain't that right, Instructor?","TWN":"教官您說是嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그 호칭은 좀 그만둬. 자네들이 교관이라고 부르니 다른 사람들도 옮았잖아.","JPN":"その呼び方はやめてくれ。あんたたちが教官って呼ぶから他の人もそう呼ぶようになったじゃないか。","ENG":"Stop calling me that. Other people started calling me that too because of you guys.","TWN":"不要再叫我教官，因為你們這樣叫我，搞得其他人也有樣學樣。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"하하, 교관님 수완이 아니었으면 저희는 아직도 이런 번듯한 장비 대신 권총 하나 달랑 들고 다녔을 걸요.","JPN":"ハハ、教官がいなかったら私たちはいまだにこんな立派な装備も使いこなせず、一丁の拳銃で戦っていたはずですよ。","ENG":"Haha, if it wasn't for you, sir, we'd still be carrying around pistols instead of proper gear like this.","TWN":"哈哈～要不是教官的手腕高明，我們怎麼可能會有這麼酷炫的裝備，頂多就一把手槍。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"레이첼한테 물어 보세요. 얘가 그렇게 안 보여도 우리 마크 만들어 준 열혈팬이거든요.","JPN":"レイチェルに聞いてみてください。そうは見えないかもしれませんが、私たちのエンブレムも作ってくれた熱血ファンなんですよ。","ENG":"Just ask Rachel. She may not look it, but she's a big fan of ours. She actually designed our logo!","TWN":"您自己問瑞秋，您別看她那樣，她還特地為我們設計專屬徽章，她可是我們的鐵粉喔！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐래. 갱단들이랑 비교하면 하도 거지떼 같아서 그려 준 거구만.","JPN":"何言ってるの。ギャングと比べるとタダの雑魚集団に見えるのが可哀そうだから描いてやっただけ。","ENG":"Oh, please. I only did it because you looked like a bunch of hobos compared to the gangs.","TWN":"討厭～那是因為和那些幫派比起來，你們實在有夠遜，我才幫你們設計的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"소중히 보관해 두셔. 내가 정식 데뷔하면 여태까지 그렸던 작품들도 이터니움값이 될 테니까.","JPN":"大事にしておいたほうがいいよ。アタシが有名になったらこれまで描いた作品は全部エタニウムぐらい価値のあるものになるんだから。","ENG":"You'd better hold onto the original drawing. Once I make my debut, everything I drew will be worth a hundred times its weight in Eternium.","TWN":"要好好保管喔！等我正式出道後，之前畫過的作品可是會像永恆之金那樣值錢喔！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"당연히 그래야지. 그 때 입던 셔츠 예쁘게 다림질해서 벽에다 걸어 뒀거든.","JPN":"もちろんそうするとも。あの時着ていたシャツはキレイにアイロンをかけて壁にかけておいたんだ。","ENG":"Of course. That shirt you made me is hanging on my wall. Neatly ironed and everything.","TWN":"那當然！之前穿過的衣服也洗好燙好後，現在掛在牆壁上呢！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"으엑. 다 큰 남자가 징그럽게.","JPN":"うぅ、それはちょっと気持ち悪いわ。","ENG":"Eww. That's kind of creepy.","TWN":"矮額，大叔你有點噁心。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"화기애애한 건 좋지만 너무 방심하지는 말도록.","JPN":"和気あいあいとするのはいいが、あまり油断するなよ。","ENG":"I appreciate the high morale, but don't let your guard down either.","TWN":"大家這樣有說有笑很好，但也不能掉以輕心。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"상대는 마젤란 예언회의 잔당들이다.","JPN":"相手はマジェラン預言会の残党だ。","ENG":"This is the MPS we're about to deal with here. Or what's left of it, anyway.","TWN":"對方可是麥哲倫預言會的餘黨！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"리플레이서 사태 전까지 도시 한복판에서 기갑병기를 운용하던 단체야. 설욕하려고 달려들 수 있어.","JPN":"リプレイサー事件までは都市のど真ん中で機甲兵器を運用していた連中だ。雪辱を果たそうとしてくる可能性もある。","ENG":"Magellan's Prediction Society used to deploy armored bots right in the middle of town before the Replacers appeared. They might try to reclaim their old glory.","TWN":"在克隆集團事件發生之前，他們可是在市中心操控機甲兵器的團體。可能是想雪恥。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"알아요. 이 동네도 송신탑 덕분에 전화는 터지니까.","JPN":"わかってますよ。この街も送信塔のおかげで電話は使えるから。","ENG":"Yeah, I know. Even in a dump like this, we still get a few bars on our phone thanks to the tower.","TWN":"我知道，這個地方也因為發射塔的關係，手機設備都集體發生爆炸。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그렇다고 엠마를 피라미드 파워로 치료할 수는 없잖아요.","JPN":"だからって、エマをピラミッドパワーなんかで治療するわけにはいかないでしょ？","ENG":"But we can't rely on pyramid power to treat Emma either.","TWN":"也因為這樣，也無法用金字塔能量治療愛瑪。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"동감이야. 멘델슨 선생님은 다 좋은데…….","JPN":"同感だ。メンデルソン先生はいい人だが……","ENG":"Agreed. I've got nothing person against Dr. Mendelssohn, but…","TWN":"同意，曼德森老師都很好……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"핸들 꺾어!","JPN":"ハンドルを切れ！","ENG":"Watch out!","TWN":"快打方向盤！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"꺄아악!? 뭐, 뭐예요! 침식체?!","JPN":"きゃああっ！？　な、何ですか？　侵食体！？","ENG":"Eeek!! W-what's going on?! C.O.s?!","TWN":"啊！？什麼東西？是侵蝕體嗎？！"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아니, 대전차 로켓이야! 예언회 녀석들이다!","JPN":"いや、対戦車ロケット弾だ！　預言会の奴らに違いない！","ENG":"No! An RPG! It's the MPS!","TWN":"不，是反坦克炮！是預言會的傢伙！"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"뒤따라오는 단원들에게 알린다! 전원 전투 준비!","JPN":"後続の団員たちに知らせる！　全員戦闘準備！","ENG":"Everyone following in the convoy, be advised! Prepare to engage!","TWN":"告訴後方人員，全部進入作戰準備！"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"제기랄! 한 방에 보낼 완벽한 기회였는데!","JPN":"くそ！　一発で仕留める完璧なチャンスだったのに！","ENG":"Damn it! That was the perfect chance to take them all out!","TWN":"可惡！錯過一次就可以送你們上西天的好機會！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HERETIC_NPC_NULL_B","text":{"KOREA":"그러게 내가 쏘겠다고 했잖아!","JPN":"だから俺が撃つって言っただろ！","ENG":"That's why I said I'll shoot!","TWN":"就是說，早知道讓我來！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"침착하라, 형제들이여!","JPN":"落ち着きたまえ、兄弟よ！","ENG":"Do not be dismayed, brethren!","TWN":"我的弟兄們，冷靜點！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"반목하지 마라! 신세계로 향하려는 우리를 방해한 자들을 처단하라!","JPN":"反目するな！　新世界へ向かう我々を邪魔した者たちを断罪せよ！","ENG":"Argue not amongst ourselves! Bring retribution to those who dare interfere with our journey to the New World!","TWN":"現在不是起內鬨的時候，快把那些妨礙我們前往新世界的傢伙除掉！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"이것은 새로운 성전일지니!","JPN":"これは新たな聖戦だ！","ENG":"For a new Temple awaits us!","TWN":"這是新的聖戰！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"오오, 엘카노 주교님! 저희를 이끄시는 예언자의 적통이시여!","JPN":"おお、エルカノ司教様！　我々を導く正統たる預言者よ！","ENG":"Oh, Bishop Elcano! The rightful heir of our Prophet!","TWN":"喔喔喔～埃爾卡諾主教！帶領我們的預言家正統繼承人！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HERETIC_NPC_NULL_B","text":{"KOREA":"주교님 말씀이 옳습니다! 저들을 처단해 이 지역 불신자들에게 본보기로 삼겠습니다!","JPN":"司教様のお言葉どおりです！　彼らを断罪してこの地域の不信者どもの見せしめにします！","ENG":"Your Holiness is right! We shall make an example of them for all the infidels to dread!","TWN":"主教說得沒錯！幹掉那些傢伙！讓這裡的人看看不信奉本教的下場！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"쳇…… 탈옥 후에 후원도 받고 일이 잘 풀리나 했더니, 이런 식으로 꼬일 줄이야.","JPN":"ちっ……脱獄後に後援も受けてうまくいくかと思いきや、こんなことになるとは。","ENG":"Hmph… Just when things started working out again, what with the money and all, after I broke out of jail…","TWN":"嗟……還想說越獄後有獲得援助，事情也都進展得很順利，沒想到殺出個程咬金！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"뭐, 차라리 잘됐군.","JPN":"まあ、むしろよかったかもしれないな。","ENG":"Oh well. I suppose this is for the best.","TWN":"不過這樣也好！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"갱단들은 싸구려 약으로 매수하면 된다지만, 자경단 행세씩이나 하는 놈들은 다를 테니까.","JPN":"ギャングどもは安物の薬で買収すればいいが、自警団の連中にはそんな手口が効くとは思えないからな。","ENG":"I could always bribe the gangs with cheap drugs, but these vigilantes are cut from a different cloth.","TWN":"幫派還可以用一些便宜貨收買打發掉， 自衛隊那些裝模作樣的傢伙可就沒那麼好打發。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"이 기회에 귀찮은 화근을 없애 주지.","JPN":"この機会に厄介者を排除してやろう。","ENG":"I might as well as get rid of this nuisance once and for all.","TWN":"不如趁這個機會，將他們除掉一勞永逸！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};